const html = $input.first().json.data || $input.first().json.body || '';
const cpf = $('Extract CPF').item.json.cpf;

let nome_extraido = 'N/A';
let processos_array = [];
let classe_extraida = 'Processo';

// Função para limpar nome extraído
function limparNome(texto) {
  if (!texto) return 'N/A';
  let limpo = texto.replace(/<[^>]+>/g, ' ');
  limpo = limpo.replace(/&nbsp;/gi, ' ').replace(/&amp;/gi, '&');
  limpo = limpo.split(/Advogado|<br/i)[0];
  limpo = limpo.replace(/[\s\n\r]+/g, ' ').trim();
  if (/^\d{2}\/\d{2}\/\d{4}/.test(limpo)) return 'N/A';
  if (limpo.length < 3) return 'N/A';
  return limpo;
}

// Detectar tipo de página
const isListPage = html.includes('Processos encontrados') || html.includes('linkProcesso');
const isSinglePage = html.includes('unj-entity-header') || 
                     (html.includes('Classe') && html.includes('Assunto') && html.includes('Foro') && html.includes('Vara'));
const naoEncontrado = html.includes('Não foram encontrados processos') || html.includes('Nenhum registro localizado');

if (naoEncontrado) {
  nome_extraido = 'N/A';
  processos_array = [];
} else if (isListPage && !isSinglePage) {
  // FORMATO LISTA (múltiplos processos)

  // Extrair NOME - usar classe nomeParte
  const nomeMatch = html.match(/class="[^"]*nomeParte[^"]*"[^>]*>\s*([^<]+)/i);
  if (nomeMatch && nomeMatch[1]) {
    nome_extraido = limparNome(nomeMatch[1]);
  }

  // Extrair cada processo da lista
  // Padrão: linkProcesso contém número, classeProcesso contém classe, dataLocalDistribuicaoProcesso contém data
  const processoBlocks = html.split(/id="divProcesso/);

  for (let i = 1; i < processoBlocks.length; i++) {
    const block = processoBlocks[i];

    // Número do processo
    const numMatch = block.match(/class="linkProcesso"[^>]*>\s*(\d{7}-\d{2}\.\d{4}\.\d\.\d{2}\.\d{4})/i);
    if (!numMatch) continue;
    const numero = numMatch[1];

    // Classe do processo
    const classeMatch = block.match(/class="classeProcesso"[^>]*>([^<]+)/i);
    const classe = classeMatch ? classeMatch[1].trim() : 'Processo';

    // Data do processo
    const dataMatch = block.match(/class="dataLocalDistribuicaoProcesso"[^>]*>([^<-]+)/i);
    const data = dataMatch ? dataMatch[1].trim() : new Date().toLocaleDateString('pt-BR');

    processos_array.push({ numero, classe, data });
  }

  // Fallback: se não encontrou processos com o método acima, usar regex global
  if (processos_array.length === 0) {
    const processoRegex = /(\d{7}-\d{2}\.\d{4}\.\d\.\d{2}\.\d{4})/g;
    let match;
    const seen = new Set();
    while ((match = processoRegex.exec(html)) !== null) {
      if (!seen.has(match[1])) {
        seen.add(match[1]);
        processos_array.push({
          numero: match[1],
          classe: 'Processo',
          data: new Date().toLocaleDateString('pt-BR')
        });
      }
    }
  }
} else if (isSinglePage) {
  // FORMATO PÁGINA ÚNICA (detalhes do processo)

  // Extrair número do processo
  const numMatch = html.match(/(\d{7}-\d{2}\.\d{4}\.\d\.\d{2}\.\d{4})/);

  // CLASSE - id="classeProcesso"
  const classeMatch = html.match(/id="classeProcesso"[^>]*>([^<]+)/i);
  if (classeMatch && classeMatch[1]) {
    classe_extraida = classeMatch[1].trim();
  }

  // NOME - classe nomeParteEAdvogado
  const nomePatterns = [
    /nomeParteEAdvogado[^>]*>[\s\n]*([A-ZÀ-Ú][A-Za-zÀ-ÿ\s]+?)(?:\s*<br|\s*Advogad)/i,
    /class="[^"]*nomeParte[^"]*"[^>]*>\s*([^<]+)/i,
    /tipoDeParticipacao["'][^>]*>Reqte[\s\S]{0,500}?>([A-ZÀ-Ú][A-Za-zÀ-ÿ\s]+?)(?:\s*<br|\s*Advogad)/i
  ];

  for (const pattern of nomePatterns) {
    const match = html.match(pattern);
    if (match && match[1]) {
      const nome = limparNome(match[1]);
      if (nome !== 'N/A' && nome.length >= 5 && !/^(Reqte|Requerente|Polo|SÃO PAULO)/i.test(nome)) {
        nome_extraido = nome;
        break;
      }
    }
  }

  if (numMatch) {
    processos_array.push({
      numero: numMatch[1],
      classe: classe_extraida,
      data: new Date().toLocaleDateString('pt-BR')
    });
  }
} else {
  // Fallback genérico
  const processoRegex = /(\d{7}-\d{2}\.\d{4}\.\d\.\d{2}\.\d{4})/g;
  let match;
  const seen = new Set();
  while ((match = processoRegex.exec(html)) !== null) {
    if (!seen.has(match[1])) {
      seen.add(match[1]);
      processos_array.push({
        numero: match[1],
        classe: 'Processo',
        data: new Date().toLocaleDateString('pt-BR')
      });
    }
  }
}

const total_processos = processos_array.length;

let responseText = 'Consulta sistema do Tribunal Judiciario\n\n';
responseText += `Prezado(a) ${nome_extraido}, CPF: ${cpf}\n\n`;

if (total_processos > 0) {
  responseText += 'Localizamos os seguintes requerimentos:\n';
  processos_array.forEach(p => {
    responseText += `${p.data} ${p.numero} ${p.classe}\n`;
  });
} else {
  responseText += 'Nenhum processo localizado para este CPF.\n';
}

responseText += `\nConsulta oficial realizada no sistema do Tribunal de Justica as ${new Date().toLocaleDateString('pt-BR')}, ${new Date().toLocaleTimeString('pt-BR', {hour: '2-digit', minute: '2-digit'})}`;

return [{
  json: {
    cpf,
    nome_extraido,
    processos_array,
    total_processos,
    responseText,
    _debug: {
      isListPage,
      isSinglePage,
      naoEncontrado,
      classe_extraida,
      htmlLength: html.length
    }
  }
}];

